import { Toc as TocRoot, type TocProps } from "./toc";
import { TocList, type TocListProps } from "./toc-list";
import { TocItem, type TocItemProps, type TocItemRenderProps, tocItemVariants } from "./toc-item";

const Toc = Object.assign(TocRoot, {
  List: TocList,
  Item: TocItem,
});

export { Toc, type TocProps };
export { TocList, type TocListProps };
export { TocItem, type TocItemProps, type TocItemRenderProps, tocItemVariants };

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export interface TocProps extends Omit<ComponentPropsWithRef<"nav">, "title"> {
  title?: string;
  as?: "h2" | "h3" | "h4";
}

export function Toc({
  title = "On this page",
  as: Heading = "h2",
  className,
  children,
  ref,
  ...props
}: TocProps) {
  return (
    <nav
      ref={ref}
      aria-label={title}
      className={cn("w-56 shrink-0 py-8 pr-4", className)}
      {...props}
    >
      <Heading className="mb-3 text-[10px] font-bold uppercase tracking-wider text-muted-foreground font-mono">
        {title}
      </Heading>
      {children}
    </nav>
  );
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type TocListProps = ComponentPropsWithRef<"ul">;

export function TocList({ className, children, ref, ...props }: TocListProps) {
  return (
    <ul
      ref={ref}
      role="list"
      className={cn("border-l border-border flex flex-col gap-1.5", className)}
      {...props}
    >
      {children}
    </ul>
  );
}

"use client";

import type {
  AnchorHTMLAttributes,
  ComponentPropsWithRef,
  CSSProperties,
  ReactNode,
  Ref,
} from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";

const INDENT_BASE_PX = 12;
const INDENT_PER_LEVEL_PX = 12;

export const tocItemVariants = cva(
  "block py-1 text-xs font-mono transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring",
  {
    variants: {
      active: {
        true: "text-primary font-bold",
        false: "text-muted-foreground hover:text-foreground",
      },
    },
    defaultVariants: {
      active: false,
    },
  },
);

export type TocItemRenderProps = AnchorHTMLAttributes<HTMLAnchorElement> & {
  ref: Ref<HTMLAnchorElement>;
  className: string;
  style: CSSProperties;
  "data-active"?: true;
};

export interface TocItemProps extends Omit<ComponentPropsWithRef<"a">, "children"> {
  children: ReactNode | ((props: TocItemRenderProps) => ReactNode);
  active?: boolean;
  /** Heading level (2 = h2, 3 = h3, etc). Values below 2 are treated as 2. */
  depth?: number;
}

export function TocItem({
  children,
  depth = 2,
  active,
  className,
  style,
  ref,
  ...props
}: TocItemProps) {
  const indent = Math.max(0, depth - 2) * INDENT_PER_LEVEL_PX + INDENT_BASE_PX;

  const renderProps: TocItemRenderProps = {
    ref: ref ?? null,
    "aria-current": active ? "location" : undefined,
    "data-active": active || undefined,
    className: cn(tocItemVariants({ active }), className),
    style: { paddingLeft: `${indent}px`, ...style },
    ...props,
  };

  if (typeof children === "function") return <li>{children(renderProps)}</li>;

  return (
    <li>
      <a {...renderProps}>{children}</a>
    </li>
  );
}
